// Filter contacts with no engagement in 45, 60, or 90 days
const contacts = $input.all();
const now = new Date();

const reengagementTiers = [];

for (const item of contacts) {
  const c = item.json;
  // Skip if already tagged as re-engagement complete or unsubscribed
  const tags = c.tags || [];
  if (tags.includes('Re-engagement Complete') || tags.includes('Unsubscribed')) continue;

  // Last contact date from GHL (use dateAdded as proxy if no engagement field)
  const lastEngaged = c.lastActivityDate || c.dateAdded;
  if (!lastEngaged) {
    // No engagement history - use dateAdded
    const addedDate = new Date(c.dateAdded);
    const daysSinceAdded = Math.floor((now - addedDate) / (1000 * 60 * 60 * 24));
    if (daysSinceAdded >= 45) {
      reengagementTiers.push({ ...c, daysSince: daysSinceAdded, tier: daysSinceAdded >= 90 ? 3 : daysSinceAdded >= 60 ? 2 : 1 });
    }
    continue;
  }

  const lastDate = new Date(lastEngaged);
  const daysSince = Math.floor((now - lastDate) / (1000 * 60 * 60 * 24));

  if (daysSince >= 45) {
    reengagementTiers.push({ ...c, daysSince, tier: daysSince >= 90 ? 3 : daysSince >= 60 ? 2 : 1 });
  }
}

// Sort by tier (most disengaged first)
reengagementTiers.sort((a, b) => b.tier - a.tier);
return reengagementTiers.map(c => ({ json: c }));
